import React, { useState, useEffect } from 'react';

const TransactionForm = ({ editingTransaction, onSubmit, onCancel, saving }) => {
  const [formData, setFormData] = useState({
    title: '',
    amount: '',
    type: 'expense',
    category: '',
    paymentMethod: 'bank_transfer',
    notes: '',
    date: new Date().toISOString().split('T')[0],
  });

  useEffect(() => {
    if (editingTransaction) {
      setFormData({
        title: editingTransaction.title || '',
        amount: editingTransaction.amount || '',
        type: editingTransaction.type || 'expense',
        category: editingTransaction.category || '',
        paymentMethod: editingTransaction.paymentMethod || 'bank_transfer',
        notes: editingTransaction.notes || '',
        date: editingTransaction.date ? new Date(editingTransaction.date).toISOString().split('T')[0] : new Date().toISOString().split('T')[0],
      });
    } else {
      setFormData({
        title: '',
        amount: '',
        type: 'expense',
        category: '',
        paymentMethod: 'bank_transfer',
        notes: '',
        date: new Date().toISOString().split('T')[0],
      });
    }
  }, [editingTransaction]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit(formData);
  };

  return (
    <div className="panel">
      <h3 className="panel-title">{editingTransaction ? 'Edit Transaction' : 'Add New Transaction'}</h3>
      <form onSubmit={handleSubmit} className="form">
        <div className="form-row">
          <div>
            <label>Title</label>
            <input
              required
              type="text"
              name="title"
              value={formData.title}
              onChange={handleChange}
              placeholder="Salary, Rent, Groceries..."
            />
          </div>
          <div>
            <label>Amount</label>
            <input
              required
              type="number"
              name="amount"
              value={formData.amount}
              onChange={handleChange}
              step="0.01"
              placeholder="0.00"
              min="0"
            />
          </div>
        </div>
        <div className="form-row">
          <div>
            <label>Type</label>
            <select name="type" value={formData.type} onChange={handleChange}>
              <option value="income">Income</option>
              <option value="expense">Expense</option>
            </select>
          </div>
          <div>
            <label>Date</label>
            <input
              required
              type="date"
              name="date"
              value={formData.date}
              onChange={handleChange}
            />
          </div>
        </div>
        <div className="form-row">
          <div>
            <label>Category</label>
            <input
              required
              type="text"
              name="category"
              value={formData.category}
              onChange={handleChange}
              placeholder="Food, Transport, Salary..."
            />
          </div>
          <div>
            <label>Payment Method</label>
            <select name="paymentMethod" value={formData.paymentMethod} onChange={handleChange}>
              <option value="bank_transfer">Bank Transfer</option>
              <option value="credit_card">Credit Card</option>
              <option value="cash">Cash</option>
            </select>
          </div>
        </div>
        <div>
          <label>Notes</label>
          <textarea
            name="notes"
            value={formData.notes}
            onChange={handleChange}
            rows="3"
            placeholder="Optional notes..."
          />
        </div>
        <div className="form-actions">
          <button type="button" className="button-ghost" onClick={onCancel}>
            Cancel
          </button>
          <button type="submit" className="button-primary" disabled={saving}>
            {saving ? 'Saving...' : (editingTransaction ? 'Update Transaction' : 'Add Transaction')}
          </button>
        </div>
      </form>
    </div>
  );
};

export default TransactionForm;
